'use client';
import { useAuth } from '@/context/authContext';
import { useRouter, usePathname } from 'next/navigation';
import { useEffect, useState } from 'react';
import { PlusIcon, PencilIcon, TrashIcon, UserCircleIcon, AcademicCapIcon, ClipboardIcon, UserGroupIcon, MegaphoneIcon } from '@heroicons/react/24/outline';
import NextLink from '@/components/NextLink';
import ProtectedRoute from '@/components/ProtectedRoute';
import LoadingModal from '@/components/ui/LoadingModal';
import useDelayedOpen from '@/hooks/useDelayedOpen';
import styles from '@/styles/admin-dashboard.module.css';

interface Anuncio {
  id: number;
  mensaje: string;
  tipo: string;
  autorId: number;
  autor: { name: string; email: string };
  materia?: { nombre: string };
  fecha: string;
}

export default function AdminAnunciosPage() {
  const { user } = useAuth();
  const router = useRouter();
  const [anuncios, setAnuncios] = useState<Anuncio[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [materias, setMaterias] = useState<any[]>([]);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [formData, setFormData] = useState({
    mensaje: '',
    tipo: 'global',
    materiaId: '',
  });

  useEffect(() => {
    if (!user) return;
    loadAnuncios();
    loadMaterias();
  }, [user]);

  const loadAnuncios = async () => {
    try {
      setLoading(true);
      const idToken = await user?.getIdToken();
      const response = await fetch('/api/admin/anuncios', {
        headers: { Authorization: `Bearer ${idToken}` },
      });

      if (response.ok) {
        const data = await response.json();
        setAnuncios(data.anuncios || []);
      } else {
        setError('Error al cargar anuncios');
      }
    } catch (err) {
      console.error('Error cargando anuncios:', err);
      setError('Error al cargar anuncios');
    } finally {
      setLoading(false);
    }
  };

  const loadMaterias = async () => {
    try {
      const idToken = await user?.getIdToken();
      const response = await fetch('/api/admin/asignaturas', {
        headers: { Authorization: `Bearer ${idToken}` },
      });

      if (response.ok) {
        const data = await response.json();
        setMaterias(data.asignaturas || []);
      }
    } catch (err) {
      console.error('Error cargando materias:', err);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.mensaje || !formData.tipo) {
      setError('Completa los campos requeridos');
      return;
    }

    try {
      const idToken = await user?.getIdToken();
      const method = editingId ? 'PUT' : 'POST';
      const url = editingId 
        ? `/api/admin/anuncios?anuncioId=${editingId}`
        : '/api/admin/anuncios';

      const response = await fetch(url, {
        method,
        headers: {
          Authorization: `Bearer ${idToken}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...formData,
          materiaId: formData.materiaId ? parseInt(formData.materiaId) : null,
          anuncioId: editingId,
        }),
      });

      if (response.ok) {
        setFormData({ mensaje: '', tipo: 'global', materiaId: '' });
        setEditingId(null);
        setShowForm(false);
        setError('');
        loadAnuncios();
      } else {
        setError('Error al guardar anuncio');
      }
    } catch (err) {
      console.error('Error guardando anuncio:', err);
      setError('Error al guardar anuncio');
    }
  };

  const handleDelete = async (anuncioId: number) => {
    if (!confirm('¿Eliminar este anuncio?')) return;

    try {
      const idToken = await user?.getIdToken();
      const response = await fetch(`/api/admin/anuncios?anuncioId=${anuncioId}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${idToken}` },
      });

      if (response.ok) {
        loadAnuncios();
      } else {
        setError('Error al eliminar anuncio');
      }
    } catch (err) {
      console.error('Error eliminando anuncio:', err);
      setError('Error al eliminar anuncio');
    }
  };

  const handleEdit = (anuncio: Anuncio) => {
    setFormData({
      mensaje: anuncio.mensaje,
      tipo: anuncio.tipo,
      materiaId: anuncio.materia?.nombre || '',
    });
    setEditingId(anuncio.id);
    setShowForm(true);
  };

  if (loading) return <div className={styles.container}><p>Cargando...</p></div>;

  return (
    <div className={styles.container}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <h1 className={styles.title}>Gestión de Anuncios</h1>
        <button
          onClick={() => {
            setFormData({ mensaje: '', tipo: 'global', materiaId: '' });
            setEditingId(null);
            setShowForm(!showForm);
          }}
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: '0.5rem',
            padding: '0.5rem 1rem',
            backgroundColor: '#007bff',
            color: 'white',
            border: 'none',
            borderRadius: '0.375rem',
            cursor: 'pointer',
          }}
        >
          <PlusIcon style={{ width: 20, height: 20 }} />
          Nuevo Anuncio
        </button>
      </div>

      {error && <div style={{ color: 'red', marginBottom: '1rem', padding: '0.5rem', backgroundColor: '#fee', borderRadius: '0.375rem' }}>{error}</div>}

      {showForm && (
        <form onSubmit={handleSubmit} style={{ marginBottom: '2rem', padding: '1.5rem', border: '1px solid #ddd', borderRadius: '0.5rem', backgroundColor: '#f9f9f9' }}>
          <div style={{ marginBottom: '1rem' }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 'bold' }}>Mensaje *</label>
            <textarea
              value={formData.mensaje}
              onChange={(e) => setFormData({ ...formData, mensaje: e.target.value })}
              placeholder="Escribe el anuncio..."
              style={{ width: '100%', minHeight: '120px', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '0.375rem' }}
            />
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
            <div>
              <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 'bold' }}>Tipo *</label>
              <select
                value={formData.tipo}
                onChange={(e) => setFormData({ ...formData, tipo: e.target.value })}
                style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '0.375rem' }}
              >
                <option value="global">Global</option>
                <option value="importante">Importante</option>
                <option value="materia">Materia</option>
                <option value="grado">Grado</option>
              </select>
            </div>

            {formData.tipo === 'materia' && (
              <div>
                <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 'bold' }}>Materia</label>
                <select
                  value={formData.materiaId}
                  onChange={(e) => setFormData({ ...formData, materiaId: e.target.value })}
                  style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '0.375rem' }}
                >
                  <option value="">Selecciona una materia</option>
                  {materias.map(m => (
                    <option key={m.id} value={m.id}>{m.nombre}</option>
                  ))}
                </select>
              </div>
            )}
          </div>

          <div style={{ display: 'flex', gap: '0.5rem' }}>
            <button
              type="submit"
              style={{ padding: '0.5rem 1rem', backgroundColor: '#28a745', color: 'white', border: 'none', borderRadius: '0.375rem', cursor: 'pointer' }}
            >
              {editingId ? 'Actualizar' : 'Crear'} Anuncio
            </button>
            <button
              type="button"
              onClick={() => {
                setShowForm(false);
                setEditingId(null);
                setFormData({ mensaje: '', tipo: 'global', materiaId: '' });
              }}
              style={{ padding: '0.5rem 1rem', backgroundColor: '#6c757d', color: 'white', border: 'none', borderRadius: '0.375rem', cursor: 'pointer' }}
            >
              Cancelar
            </button>
          </div>
        </form>
      )}

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(400px, 1fr))', gap: '1.5rem' }}>
        {anuncios.map(anuncio => (
          <div key={anuncio.id} style={{ border: '1px solid #ddd', padding: '1.5rem', borderRadius: '0.5rem', backgroundColor: '#f9f9f9' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: '0.5rem' }}>
              <span style={{ display: 'inline-block', padding: '0.25rem 0.75rem', backgroundColor: anuncio.tipo === 'importante' ? '#dc3545' : '#007bff', color: 'white', fontSize: '0.75rem', fontWeight: 'bold', borderRadius: '0.25rem' }}>
                {anuncio.tipo.toUpperCase()}
              </span>
              <div style={{ display: 'flex', gap: '0.5rem' }}>
                <button
                  onClick={() => handleEdit(anuncio)}
                  style={{ padding: '0.25rem 0.5rem', backgroundColor: '#ffc107', border: 'none', borderRadius: '0.25rem', cursor: 'pointer' }}
                >
                  <PencilIcon style={{ width: 14, height: 14 }} />
                </button>
                <button
                  onClick={() => handleDelete(anuncio.id)}
                  style={{ padding: '0.25rem 0.5rem', backgroundColor: '#dc3545', color: 'white', border: 'none', borderRadius: '0.25rem', cursor: 'pointer' }}
                >
                  <TrashIcon style={{ width: 14, height: 14 }} />
                </button>
              </div>
            </div>
            <p style={{ margin: '0.75rem 0', lineHeight: '1.5', color: '#333' }}>{anuncio.mensaje}</p>
            <div style={{ color: '#888', fontSize: '0.875rem' }}>
              <p style={{ margin: '0.25rem 0' }}>Por: {anuncio.autor?.name || 'Admin'}</p>
              <p style={{ margin: '0.25rem 0' }}>Fecha: {new Date(anuncio.fecha).toLocaleDateString()}</p>
            </div>
          </div>
        ))}
      </div>

      {anuncios.length === 0 && !loading && (
        <p style={{ textAlign: 'center', color: '#888' }}>No hay anuncios creados aún.</p>
      )}
    </div>
  );
}
